#include <bits/stdc++.h>
using namespace std;
#define LL long long
inline LL gcd(int a, int b) {
	return ((!b)?(a):(gcd(b,a%b)));
}
inline LL lcm(int a, int b) {
	return a/gcd(a,b)*b;
}
int main(void) {
	LL t;
	cin>>t;
	while(t--) {
		LL ans=0,a0,a1,b0,b1;
		cin>>a0>>a1>>b0>>b1;
		for(int i=1;i*i<=b1;i++) {
            if(b1%i)continue;
			if(gcd(i,a0)==a1&&lcm(i,b0)==b1)ans++;
            if(b1/i==i)continue;;
			if(gcd(b1/i,a0)==a1&&lcm(b1/i,b0)==b1)ans++;
		}
		cout<<ans<<"\n";
	}
	return false;
}
